import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./ConsultancyPage.css";

const API_BASE = (process.env.REACT_APP_API_BASE || "http://localhost:5000/api").replace(/\/+$/, "");

function ConsultancyPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState("");
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // fallback seed
  const seed = useMemo(() => ({
    "General Physician": [
      {
        name: "Dr. Rachna Kucherira",
        img: "https://cdn.pixabay.com/photo/2016/03/31/20/11/doctor-1295568_960_720.png",
        details: "MD (Community Medicine), AIIMS New Delhi — 30+ years of experience",
        languages: "Speaks Hindi, English",
        fee: "₹1000",
      },
      {
        name: "Dr. Rashmi Gupta Bajpai",
        img: "https://cdn.pixabay.com/photo/2014/04/03/10/32/doctor-310845_960_720.png",
        details: "MBBS Govt Medical College, Trivandrum — 24+ years of experience",
        languages: "Speaks Hindi, English, Malayalam, Punjabi",
        fee: "₹700",
      },
    ],
    Pediatrics: [
      {
        name: "Dr. Aarav Mehta",
        img: "https://cdn.pixabay.com/photo/2016/03/31/20/11/doctor-1295568_960_720.png",
        details: "MD (Pediatrics), AIIMS Delhi — 15+ years of experience in child care",
        languages: "Speaks Hindi, English",
        fee: "₹850",
      },
    ],
  }), []);

  const [doctorsData, setDoctorsData] = useState(seed);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${API_BASE}/public/doctors`);
        const list = await res.json();
        if (Array.isArray(list) && list.length) {
          // group by specialty
          const grouped = {};
          list.forEach((d) => {
            const key = d.specialty || "General";
            if (!grouped[key]) grouped[key] = [];
            grouped[key].push({
              name: d.name,
              img: d.avatar || "https://cdn.pixabay.com/photo/2016/03/31/20/11/doctor-1295568_960_720.png",
              details: d.bio || d.specialty || "",
              languages: Array.isArray(d.languages) ? `Speaks ${d.languages.join(", ")}` : "",
              fee: d.fee ? `₹${d.fee}` : "₹700",
            });
          });
          setDoctorsData(grouped);
        }
      } catch (_) {
        // keep seed
      }
    })();
  }, []);

  const allDoctors = Object.keys(doctorsData).flatMap((category) =>
    doctorsData[category].map((doc) => ({ ...doc, category }))
  );

  const suggestions = allDoctors.filter((doc) =>
    doc.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleSuggestionClick = (doctor) => {
    setActiveDropdown(doctor.category);
    setSearchQuery(doctor.name);
    setShowSuggestions(false);
    const section = document.getElementById(doctor.category.replace(/\s+/g, "-"));
    if (section) section.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <div className="consultancy-page">
      <div className="consultancy-header">
        <h1>Our Doctors</h1>
        <p>
          We have handpicked some of the best doctors in key specialties. Whether
          you’re looking for a General Physician or a Pediatrician — you’ll find
          trusted professionals here.
        </p>

        <div className="search-container">
          <div className="search-bar">
            <input
              type="text"
              placeholder="Search doctor name..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setShowSuggestions(true);
              }}
            />
            <button onClick={() => setShowSuggestions(false)}>Search</button>
          </div>

          {showSuggestions && searchQuery && (
            <ul className="suggestions-list">
              {suggestions.length > 0 ? (
                suggestions.map((doc, index) => (
                  <li key={index} onClick={() => handleSuggestionClick(doc)}>
                    <strong>{doc.name}</strong> <span>({doc.category})</span>
                  </li>
                ))
              ) : (
                <li className="no-suggestion">No doctor found</li>
              )}
            </ul>
          )}
        </div>
      </div>

      <div className="doctor-sections">
        {Object.keys(doctorsData).length === 0 ? (
          <p>No doctors added yet.</p>
        ) : (
          Object.keys(doctorsData).map((category, index) => (
            <div key={index} id={category.replace(/\s+/g, "-")} className="doctor-category">
              <div
                className="category-header"
                onClick={() =>
                  setActiveDropdown(activeDropdown === category ? null : category)
                }
              >
                <h2>{category}</h2>
                <span className={`arrow ${activeDropdown === category ? "open" : ""}`}>▼</span>
              </div>

              {activeDropdown === category && (
                <div className="doctor-list">
                  {doctorsData[category].map((doc, i) => (
                    <div className="doctor-card" key={i}>
                      <img src={doc.img} alt={doc.name} />
                      <div className="doctor-info">
                        <h3>{doc.name}</h3>
                        <p>{doc.details}</p>
                        <p className="languages">{doc.languages}</p>
                        <div className="consultation">
                          <span>{doc.fee} per consultation</span>
                          <div className="buttons">
                            <button className="view-btn">View Profile</button>
                            <button className="book-btn">Book Appointment</button>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default ConsultancyPage;
